  function pronunciationTargets() { const lesson = getLesson(); return [lesson.model, lesson.example, ...lesson.vocabulary.slice(0, 4).map(v => v[2])]; }
  function renderPronunciation() { const targets = pronunciationTargets(); pronunciationIndex %= targets.length; $('pronunciationTarget').textContent = targets[pronunciationIndex]; }
  async function runPronunciation() {
    const target = $('pronunciationTarget').textContent; $('pronunciationMic').classList.add('listening'); $('pronunciationStatus').textContent = 'Ouvindo...';
    startSpeechRecognition(async heard => {
      $('pronunciationMic').classList.remove('listening'); $('pronunciationHeard').textContent = heard; const score = similarity(target, heard); $('pronunciationPercent').textContent = `${score}%`; $('pronunciationScoreBadge').textContent = `${score}% nesta tentativa`; state.pronunciationScores.push({ date: localDateKey(), target, heard, score }); state.skills.speaking = clamp(state.skills.speaking + score / 100 * 2, 0, 100); state.dailySteps.pronunciation = score >= 55;
      const ai = await GraceAI.ask('pronunciation', { target, heard, score, profile: studentProfile(), memory: memorySummary() });
      const feedback = ai?.feedback || pronunciationFallback(target, heard, score); if (ai) applyAiMemory(ai); if (score < 70) addError('Pronúncia e clareza', heard, target); saveState(false); $('pronunciationFeedback').innerHTML = `<div class="grace-mini">G</div><p>${escapeHtml(feedback)}</p>`;
    }, () => { $('pronunciationMic').classList.remove('listening'); $('pronunciationStatus').textContent = 'Não consegui ouvir. Tente novamente no Chrome ou Edge.'; });
  }
  function pronunciationFallback(target, heard, score) { const targetWords = normalize(target).split(' '), heardWords = new Set(normalize(heard).split(' ')), missing = targetWords.filter(w => w.length > 3 && !heardWords.has(w)).slice(0, 4); return score >= 80 ? 'Muito bom. Agora repita com ritmo natural, sem acelerar.' : `Repita mais devagar. Dê atenção a: ${missing.join(', ') || 'finais das palavras e ritmo'}.`; }
  function similarity(a, b) { const x = normalize(a), y = normalize(b); if (!x || !y) return 0; const distance = levenshtein(x, y); return Math.round(clamp((1 - distance / Math.max(x.length, y.length)) * 100, 0, 100)); }
  function levenshtein(a, b) { const row = Array.from({ length: b.length + 1 }, (_, i) => i); for (let i = 1; i <= a.length; i++) { let prev = row[0]; row[0] = i; for (let j = 1; j <= b.length; j++) { const temp = row[j]; row[j] = Math.min(row[j] + 1, row[j - 1] + 1, prev + (a[i - 1] === b[j - 1] ? 0 : 1)); prev = temp; } } return row[b.length]; }

  function resetConversation() {
    const key = $('conversationScenario').value, scenario = conversationScenarios[key]; $('conversationRole').textContent = `${scenario.role} • nível ${appLevel()}`; $('conversationChat').innerHTML = ''; addChat('grace', scenario.opening, '', $('conversationHelp').value === 'high' ? scenario.translation : ''); lastReply = scenario.opening; speak(scenario.opening); renderQuickReplies();
  }
  function renderQuickReplies() { const lesson = getLesson(); $('quickReplies').innerHTML = [`Could you speak more slowly, please?`, lesson.model.split(/[.!?]/)[0] + '.', 'I need a moment to think.'].map(text => `<button class="quick-reply" data-quick="${escapeHtml(text)}">${escapeHtml(text)}</button>`).join(''); }
  function addChat(role, text, correction = '', translation = '') { const message = document.createElement('div'); message.className = `message ${role}`; message.innerHTML = `${escapeHtml(text)}${translation ? `<span class="translation">${escapeHtml(translation)}</span>` : ''}${correction ? `<span class="correction">${escapeHtml(correction)}</span>` : ''}`; $('conversationChat').appendChild(message); $('conversationChat').scrollTop = $('conversationChat').scrollHeight; }
  async function sendConversation(predefined = '') {
    const input = predefined || $('conversationInput').value.trim(); if (!input) return; const scenarioKey = $('conversationScenario').value, help = $('conversationHelp').value; addChat('user', input); $('conversationInput').value = ''; $('conversationStatus').textContent = 'Grace está pensando...';
    const history = state.conversationHistory[scenarioKey] || []; history.push({ role: 'user', text: input });
    const ai = await GraceAI.ask('conversation', { message: input, scenario: scenarioKey, help, history: history.slice(-12), lesson: getLesson(), memory: memorySummary(), profile: studentProfile(), level: appLevel() });
    let reply, correction, translation;
    if (ai) { reply = ai.reply || ai.next_question || 'Tell me more, please.'; correction = [ai.correction, ai.explanation].filter(Boolean).join(' — '); translation = help === 'high' ? ai.translation || '' : ''; applyAiMemory(ai); }
    else { const fallback = conversationFallback(input, scenarioKey); reply = fallback.reply; correction = fallback.correction; translation = help === 'high' ? fallback.translation : ''; }
    history.push({ role: 'assistant', text: reply }); state.conversationHistory[scenarioKey] = history.slice(-20); state.conversations++; state.skills.speaking = clamp(state.skills.speaking + 1.5, 0, 100); state.dailySteps.conversation = true; state.xp += 8; recordActivity(3); saveState(false); addChat('grace', reply, correction, translation); lastReply = reply; speak(reply); $('conversationStatus').textContent = GraceAI.getStatus().online ? 'Grace AI conectada' : 'Modo local'; $('conversationMemory').textContent = memorySummary(); renderDashboard(); renderReports();
  }
  function conversationFallback(input, scenarioKey) { const n = normalize(input), short = n.split(' ').length < 5; if (/i am work/.test(n)) return { reply: 'Good effort. What do you usually do at work?', correction: 'Use “I work”, não “I am work”.', translation: 'Bom esforço. O que você costuma fazer no trabalho?' }; const prompts = { daily: 'What was the best part of your day?', meeting: 'What is the main risk and the next action?', interview: 'What professional achievement are you most proud of?', client: 'What action will you take and when will you update me?', technology: 'What is the main security benefit of this architecture?', biblical: 'How can you apply that lesson in your daily life?' }; return { reply: short ? 'Good start. Please answer with one reason and one example.' : prompts[scenarioKey], correction: short ? 'Amplie sua resposta para praticar frases completas.' : 'Boa resposta. Continue.', translation: 'Continue e acrescente um exemplo.' }; }

  function addGamePoints(points, message) { state.gameScore += points; state.xp += points; state.dailySteps.game = true; recordActivity(2); saveState(); toast(`${message} +${points} pontos`); }
  function renderGames() { $('gameScoreBadge').textContent = `${state.gameScore} pontos hoje`; if (!matchRound.length) newMatchRound(false); if (!sentenceRound) newSentenceRound(false); if (!listeningRound) newListeningRound(false); if (!speedPrompt) newSpeedRound(false); }
